namespace Server
{
    /// <summary>
    /// Constants describing this fork's deviations from upstream. Logged at server boot
    /// (see <see cref="MainServer.Main"/>) so operators can identify which fix set is
    /// active when reading logs. Per-event runtime log lines for each fix carry a
    /// matching <c>[fix:BUG-XXX]</c> prefix so operators can grep for an individual
    /// fix's behavior.
    ///
    /// Add a new entry to <see cref="ActiveFixes"/> at the same time as the
    /// corresponding fix's commit message references it, and keep the order
    /// in commit-chronological order (oldest first).
    /// </summary>
    public static class ForkBuildInfo
    {
        public const string ForkName = "Majestic95/LunaMultiplayer";

        public static readonly string[] ActiveFixes =
        {
            "BUG-051a",    // Server-side NewSubspace request dedup
            "BUG-001",     // Solo-subspace catch-up suppression
            "BUG-003/004", // Symmetric future-subspace interpolation cap
            "BUG-051b",    // Client steady-state retry while stuck-at-warp
            "BUG-005/006", // Cross-subspace lock keying + protocol bump
            "BUG-013",     // Reaction-wheel stateString locale-normalisation
            "BUG-008-A",   // Client-side PQS-aware spawn-altitude re-alignment (Phase A)
            "BUG-045",     // Breaking Ground deployable science vessels now sent to server (ported from upstream Release/0_29_2)
            "vessel-load-budget", // Per-tick proto-reload budget + VesselLoadOutcome enum + SPACECENTER/EDITOR fast path (ported from upstream Release/0_29_2)
            "vessel-sync-log",    // Client-side append-only diagnostic trace at Logs/LMP/VesselSyncLog.txt + Reason wire field on VesselProtoMsgData (ported from upstream Release/0_29_2)
            "BUG-010",     // Disconnect handshake Part A: server broadcasts VesselPinned for each lock-owned vessel before fanning out lock releases; remaining clients hold the vessel immortal until the original pilot reconnects or another player takes the helm
            "BUG-010-B",   // Disconnect handshake Part B: client flushes a fresh proto for every locally-owned vessel before NetworkConnection.Disconnect, so server's on-disk snapshot reflects the actual moment-of-disconnect pose (matters for dock-then-logoff -> undock-child-pose). Clean disconnects only; ungraceful drops rely on Part A alone.
            "BUG-033",     // ScenarioStoreSystem.BackupScenarios now serializes each scenario under the matching per-scenario writer lock (ScenarioDataUpdater.GetSemaphore), so ConfigNode.ToString() no longer races AddNode/RemoveNode/ReplaceNode on the same instance. Was a critical-but-rare server-crash class: backup task's collection-modified exception killed the worker.
            "BUG-025",     // R&D tech node duplicate-purchase race. Server synchronously checks the canonical scenario before relaying a ShareProgressTechnologyMsgData; if the tech is already unlocked (the sender's open R&D panel was stale relative to another player's broadcast, or they clicked within sub-RTT), server sends ShareProgressTechnologyRejectedMsgData back to the sender so the client refunds the science it locally deducted. Additive wire enum value (TechnologyRejected = 11); no protocol bump.
            "BUG-023",     // Astronaut Complex desync / Tracking-Station info-pane freeze / scene-FLIGHT black scene / FixedUpdate NRE storm — all driven by null entries in ProtoPartSnapshot.protoModuleCrew that stock KSP appends when wire-side crew names don't resolve through CrewRoster. Three-part fix ported from upstream Release/0_29_2 (Drew Banyai, d3223931 + 138c2b3e): (1) VesselLoader.ScrubInvalidProtoCrew strips nulls in lockstep with protoCrewNames at vessel-load time, (2) VesselProtoSystem.CheckVesselsToLoad drains queued KerbalProto messages before each vessel-load batch to close the receiving-side timing race, (3) Part_RegisterCrew + KnowledgeBase_GetVesselCrewByAvailablePart Harmony patches as defense-in-depth for the autosave Save+Load round-trip that re-introduces nulls.
            "BUG-008-pack", // Phase A item 4a: pack-on-load + delayed unpack. PqsAlignmentRoutine now packs a freshly-loaded surface vessel (LANDED/SPLASHED/PRELAUNCH) that arrived in physics range (packed==false) on a PQS body, runs the PQS stabilise wait, snaps if NeedsRealignment, yields one FixedUpdate, and unpacks. Closes the residual polygon-scramble window where the immediate PQS sample happened to agree with stored altitude but the high-LOD mesh streamed in seconds later and exploded the collider. Active vessel never packed (would judder the camera); already-packed vessels stay on the existing snap-only path. Client-only change, no wire payload, no protocol bump.
            "per-agency-career", // Stage 5 scaffolding: PerAgencyCareer setting (default false) + protocol bump 0.30.0 -> 0.31.0. Setting=false preserves shared-agency behaviour bit-for-bit; the bump exists because per-agency wire payloads (later Stage 5 steps) will be a hard break against 0.30.x peers. No cross-compat row in LmpVersioning.cs — same break pattern as BUG-005/006 at 0.30.0.
            "MKS-R0",      // USITools depot-list authority fix. CLIENT-ONLY fix; advertised on this server-side list for operator banner visibility — actual patch lives in LmpClient.Harmony.ModuleLogisticsConsumer_DepotListPostfix. First pure-client entry in ActiveFixes; precedent for future R-fixes. Client-side Harmony postfixes on ModuleLogisticsConsumer.GetResourceStockpiles + GetPowerDistributors trim the returned vessel lists to only those whose Update lock is held by the local player, so MKS' CheckLogistics / FetchResources / PushResources never write PartResource.amount on a vessel another client owns. Closes the warehouse-balance oscillation loop between every consumer + each LMP-side VesselResourceMessageSender pulse. Per-agency dovetail is structural via Stage 5.17a — no extra agency gate needed. Imperative Harmony registration (USITools is not a compile-time dep); graceful no-op when USITools is not installed.
            "MKS-R1",      // MKS kolony-proximity subspace policy. CLIENT-ONLY fix; advertised here for operator banner visibility — actual routine lives in LmpClient.Systems.Warp.KolonyProximityWarpRoutine. Sibling to WarpSystem.WarpIfSpectatingToController: when the local active vessel is in physics-load range of another player's Update-lock-held MKSModule-bearing vessel, snap the local subspace forward to match the foreign controller's subspace so MKS' KolonizationManager / lastCheck time-base reads (Planetarium.GetUniversalTime) happen in a coherent UT across the co-present cohort. Closes the cross-vessel kolony-accrual drift under shared-scenario mode; defense-in-depth under per-agency mode (Phase 3 still partitions the scenario state itself). Jank protection: SafeToSync atmospheric/orbital-decay gate, baseline-warp gate, pre-snap pack + delayed unpack (BUG-008-A precedent), one-direction-only via WarpIfSubspaceIsMoreAdvanced (no backward snap), 10s cooldown, operator screen messages with player name. MKS-module identity resolved via string-typed reflection (MKS is not a compile-time dep); graceful no-op when MKS is not installed.
            "BUG-039",     // Custom XML elements in gameplaysettings.xml silently dropped on first server save. Operators reported wanting to add custom <CustomTag>value</CustomTag> elements (mod settings, metadata, comments-as-elements) to their gameplaysettings.xml; the server's load-then-Save cycle (SettingsBase.Load at SettingsBase.cs:30-31, "We call the save to add the new settings into the file") fed the XML through XmlSerializer which silently drops unrecognised child elements, then re-wrote the file without them. Fix: GameplaySettingsDefinition adds an [XmlAnyElement] public field CustomElements (XmlElement[]) that captures unrecognised children at deserialise time and round-trips them on serialise. Public FIELD (not property) is deliberate — System.Reflection.GetProperties() does not return fields, so SettingsHandler.HasDifferencesAgainstGivenSetting's preset-comparison reflection (SettingsHandler.cs:65-71) doesn't see it and there's no null-deref hazard / false flip-to-Custom for operators with custom elements. Custom elements move to the end of the parent on round-trip (XmlSerializer ordering for [XmlAnyElement]). Scoped to GameplaySettingsDefinition only — the bug is filed against gameplaysettings.xml specifically (#587); if operators request the same shape on the other 11 settings files, replicate the field there.
            "BUG-036",     // Mod difficulty/gameplay parameters reset on rejoin (#548, #587). CLIENT-ONLY fix; advertised here for operator banner visibility — actual patch lives in LmpClient/MainSystem.cs. MainSystem.StartGameNow used to wholesale-assign HighLogic.CurrentGame.Parameters = SettingsSystem.ServerSettings.ServerParameters, which nuked any mod-added GameParameterSection subclasses (CTB / Kerbal Engineer / etc.) registered on HighLogic.CurrentGame.Parameters but not present in LMP's wire schema. Fix: new SetParams helper assigns the six predefined KSP sections individually (Flight / Editor / TrackingStation / SpaceCenter / Difficulty / Career) instead of wholesale, so mod-registered sections survive rejoin. Existing SetAdvancedParams + SetCommNetParams already used the section-preserving CustomParams<T>() helper and remain unchanged. Ported from upstream PR #594 (iddqd0, 2025-08); the PR sat idle since filing and the symptom is recurring on operator-tracked installs.
            "BUG-037",     // Server console colour-bleed between concurrent log lines. BaseLogger.Emit (renamed from WriteLog) now acquires a private static ConsoleLock around the Console.ForegroundColor / BackgroundColor / WriteLine / ResetColor sequence so each log line's colour trio is atomic. AfterPrint (file append + ring buffer add) runs outside the lock so disk latency doesn't extend contention. Partial fix only: the inventory entry also calls out "mangled backspaces" / "output overwrites in-progress operator input" — those need a Console.ReadLine replacement / line-editor with terminal-emulator-aware re-emit; out of scope for this commit and noted in the bug-inventory residual.
            "BUG-038",     // XML prologue encoding mismatch in server config files (LunaMultiplayer#602). LunaXmlSerializer's pipeline used StringWriter, whose hard-coded UTF-16 Encoding property is read by XmlSerializer / XmlDocument.Save when writing the <?xml ?> declaration, while the disk write (File.WriteAllText) is UTF-8 no-BOM — producing files that declare utf-16 but contain UTF-8 bytes. Fix wraps the three internal StringWriter sites in a private Utf8StringWriter subclass that overrides Encoding => UTF8. Symmetric patch applied to Tools/AdminGui/LunaServerGui/Services/SettingsXmlService.cs to preserve the documented byte-equivalence contract between the server-side serializer and the Admin GUI's duplicated pipeline; without it, every operator-edited file would ping-pong its prologue on each server save. Backward compat: pre-fix utf-16-prologue files load cleanly (StreamReader BOM-detects + falls back to UTF-8). First save post-update rewrites the prologue once (ContentChecker length-compare detects it); subsequent saves no-op.
            "S1-Couple",   // Mod-compat S1 (per-agency couple reconciler). Server-side reconciliation of lmpOwningAgency on the surviving vessel after Part.Couple collapses two vessels into one. Covers stock docking AND KAS pipe coupling identically (both ride Part.Couple → VesselCoupleMsgData on the same handler). Rule: kept-wins unless kept was Unassigned (pre-0.31 sentinel per spec §10 Q3) and merged was tracked — in which case adopt merged's stamp to preserve agency continuity past the upgrade window. Cross-agency couples (both stamps non-Empty, differ) emit a Warning for operator visibility (Invariant 8); same-agency and both-Empty cases are silent no-ops. Implementation lives in Server/System/Agency/AgencyVesselCoupleReconciler.cs (pure helper, no AgencySystem lock needed — mutates the vessel's own Fields collection, not any AgencyState dict). Invoked from VesselMsgReader.HandleVesselCouple after the existing cross-agency dominant-vessel guard (5.17a write-path counterpart) and authority-subspace update, but BEFORE RemoveVessel so the merged vessel's stamp is still readable. Dual-mode silence under gate=off (PerAgencyCareer=false or non-Career game mode).
            "S6-ProtoStamp", // Mod-compat S6 (KIS re-attach restamp). CLIENT-ONLY fix; advertised here for operator banner visibility — actual change lives in LmpClient/VesselUtilities/VesselSerializer.cs. KSP's ProtoVessel.Save strips unknown top-level ConfigNode fields like lmpOwningAgency on every owner resend, so the periodic-broadcast relay path was carrying the field absent and peer-side AgencySystem.VesselOwnership mirrors were stuck on the previously-recorded value until the next VesselSync. PreSerializationChecks now re-asserts lmpOwningAgency from AgencySystem.Singleton.TryGetOwningAgency when the vessel is known to the local mirror with a non-Empty agency. Deliberately NOT stamping from LocalAgencyId on unknown / Unassigned-known vessels — that fallback would corrupt peer mirrors under three races (reconnect-window, pre-0.31 Unassigned upgrade, transferagency-lag); the AgencyMembership.DetermineOutboundStamp helper signature does not even accept the local agency so a future contributor adding the fallback has to plumb it in explicitly. Server-side branch (a)/(b)/(c) of VesselDataUpdater.RawConfigNodeInsertOrUpdate already produces correct canonical state in all these cases (it resolves senderAgencyId from PlayerName, not the wire field); the stamp matters only for peer mirrors which read the wire field directly. Operators upgrading from a prior 0.31 build need to redeploy LmpClient.dll to GameData/LunaMultiplayer/Plugins/ to pick up the change. Closes the "Unassigned" cosmetic flicker peer clients see on KIS-attach-to-known-vessel and on periodic owner resends. Dual-mode silence under gate=off.
            "MKS-R2",      // Phase 3 per-agency MKS routing (umbrella entry). Slice B (kolony): AgencyKolonyRouter intercepts AgencyKolonyStateMsgData (slot 6) — vessel-and-body keyed partition; client postfix on KolonyTools.KolonizationManager.TrackLogEntry; projector strip-then-splice on KolonizationScenario (KOLONY_ENTRY children); WarnAboutSharedKolonyOnUpgrade + hazard-gate refusal. Slice C (planetary): AgencyPlanetaryRouter intercepts AgencyPlanetaryStateMsgData (slot 7) — body-and-resource keyed partition (NOT vessel-keyed; planetary entries do NOT migrate on transferagency per pre-spec §4.e); client postfix on KolonyTools.PlanetaryLogistics.ModulePlanetaryLogistics.LevelResources (PRIVATE method anchor — AccessTools.Method resolves via BindingFlags.NonPublic; reads post-mutation StoredQuantity from PlanetaryLogisticsManager.Instance.PlanetaryLogisticsInfo via reflection); projector strip-then-splice on PlanetaryLogisticsScenario (LOGISTICS_ENTRY children); WarnAboutSharedPlanetaryOnUpgrade fires on non-zero StoredQuantity (skeleton zero-balance entries don't false-fire); hazard-gate refusal extended; flip-back-out scan extended to detect frozen PLANETARY_ENTRIES disk blocks. Slice D-1 (orbital, server-side foundation): AgencyOrbitalRouter intercepts AgencyOrbitalStateMsgData (slot 8) — TransferGuid-keyed partition (direct Guid, no string composition); cross-agency gate on DESTINATION vessel (not Origin — Deliver-time authority is destination-side per pre-spec §2.d); defensive Buffer.BlockCopy of PayloadBytes (first Phase 3 entry with mutable byte[]); projector strip-then-splice on ScenarioOrbitalLogistics (TRANSFER children at scenario root, NOT under a container); SendOrbitalStateToOwner + SendOrbitalCatchupTo wired into HandshakeSystem after planetary catchup (unconditional under gate=on); AgencyMessageHandler stub case + IgnoredScenarios entry; WarnAboutSharedOrbitalOnUpgrade fires on any TRANSFER child (no zero-balance filter — every transfer represents real in-flight or recently-completed work; pending Status=Launched transfers have already paid launch-cost fuel + deducted payload from Origin so strip-on-upgrade is the MOST asymmetric of the three MKS strips); hazard-gate refusal extended; flip-back-out scan extended for ORBITAL_TRANSFERS with strongest operator-advice posture (frozen orbital entries are MOST hazardous of the three — stale Status + StartTime/Duration). Slice D-2 (client-side) ships the gate-state-independent Deliver-prefix (OrbitalDeliveryGate.ShouldExecuteDelivery decision helper + OrbitalLogisticsTransferRequest_DeliverPrefix mutating Status=Failed+StatusMessage before returning false to avoid the ScenarioOrbitalLogistics.cs:194 inner-while hang) + IEnumerator-wrapper postfix on Deliver (terminal-Status echo — wraps __result rather than [HarmonyPatch("set_Status")] because Status is a public field at OrbitalLogisticsTransferRequest.cs:78, no setter to patch) + state-machine postfixes on DoFinalLaunchTasks (Launched echo — catches both fresh-launch AND resumed-from-Returning via the single anchor) and Abort (Returning echo) + AgencyOrbitalSender (TaskFactory+NetworkSender two-liner, early-return on empty per AgencyOrbitalStateMsgData asymmetry contract) + shared OrbitalLogisticsReflection helper (reflection cache + entry-builder + endian-safe TransferGuid SHA1-derivation from (origin, destination, startTime, duration) stable across scene reload + per-site one-shot failure log) + HarmonyPatcher.PatchOrbitalLogisticsTransferRequest (all-or-nothing on 3 method resolves + boot-time field/property resolve diagnostic for MKS-version-mismatch operators) + 20 LmpClientTest decision-helper cases (every decision-table row including null lock owner and empty-lock-under-same-agency) + 6 MockClientTest e2e routing cases. Closes the per-frame double-spend hazard pre-spec §1.c under BOTH gate=on and gate=off (strict improvement on pre-Phase-3 shared-mode baseline). All slices: IgnoredScenarios Option B gate-conditional suppression; AgencyMessageHandler stub case prevents "Unknown AgencyMessageType" log spam on existing 0.31 clients; persistence under gate=off freezes per-agency state on disk and lets shared 30s SHA pass run unchanged (strict dual-mode silence). Q1 (Slice B: ModuleColonyRewards.cs:33 manager-anchored catches all entry sources; Slice C: LevelResources is the correct anchor per pre-spec §2.a — TrackLogEntry can't be used because PlanetaryLogisticsEntry lacks vessel-id) + Q2 (Slice B: kolony entry currency cycles via stock Funding/RnD/Reputation through band-1 routers; Slice C: planetary entries don't interact with stock currency) + Q3 (Slice C: gate=off (BodyIndex, ResourceName) same-key collision is documented as known limitation per pre-spec §4.b — fixed only by gate=on per-agency partition) verified at impl.
            "v4-proto-write-guard", // VesselProto cross-agency write guard. The Stage 5.17a write-path counterpart (session 19 soak Finding 2) gated 11 relayed vessel-message types + Remove + Couple but was NOT extended to HandleVesselProto. The omission was rationalised by the "relayed proto bytes are advisory" framing at the relay surface, but that framing concerned peer-client interpretation only — the SERVER's authoritative store DID get overwritten by the proto bytes (the 5.16b stamp-preservation only preserves OwningAgencyId; the rest of the proto payload — crew list, parts, resources, position — was unprotected). The hole was uncovered during the s39 WOLF Phase 4 pre-spec multi-lens review when verifying §1.b's "Bob seizes Alice's kerbal" trace. Fix is a single RejectIfCrossAgencyWrite call in HandleVesselProto between the past-subspace check and the sender-agency resolution. Reuses the existing helper; bypass cases mirror the existing pattern (gate off / vessel not in store / Empty-sentinel / sender no agency). Vessel-not-in-store bypass is CORRECT for the proto path because proto is the legitimate entry point for new vessels and the 5.16b stamp logic at VesselDataUpdater.cs:152-154 routes them to the sender's own agency. Closes the broad cross-agency vessel-state-write exploit class — modified clients crafting protos for other agencies' vessel-ids to mutate any field. Documented limitation: race-craft-pre-create — Bob could pre-broadcast a proto for a vessel-id Alice is about to create, locking her out (narrow exploit, narrow attack surface, deferred to Stage 6). v4 protocol stays at 0.31.0 (no wire change). Dual-mode silence: under PerAgencyCareer=false the guard returns false immediately, vanilla relay behaviour preserved. See docs/research/v4-vessel-proto-cross-agency-write-guard.md for the full threat model + trace + test plan.
            "WOLF-R4", // Phase 4 per-agency WOLF (MKS Wireless Orbital Logistics Function — umbrella entry covering Slices A through F). Slice A (95b65711) shipped the wire shape + AgencyState persistence (5 dicts: WolfDepots / WolfRoutes / WolfHoppers / WolfTerminals / WolfCrewRoutes; 8 entity classes + 5 wire MsgData; enum slots 9-13 on AgencyMessageType; symmetric SubTypeDictionary appends; ToConfigNode + FromConfigNode round-trip with forward-compat). Slice B (f041fd8d) shipped the server-side depot routing foundation: AgencyWolfDepotRouter (per-entry try/catch isolation; cross-agency lock; Upsert with defensive-copy of ResourceStreams) + AgencySystemSender extensions (SendWolfDepotStateToOwner + SendWolfDepotCatchupTo, wired into HandshakeSystem catchup after orbital) + AgencyMsgReader dispatch case for WolfDepotState (slot 9) + client-side AgencyWolfDepotSender stub (TaskFactory.StartNew offload pattern). Slice B-2 (b7a3e568) shipped atomic activation: AgencyScenarioProjector WOLF_ScenarioModule splice + IgnoredScenarios Option B gate-conditional filter + WarnAboutSharedWolfOnUpgrade boot-time diagnostic + hazard-gate refusal predicate + 3 client postfixes (ScenarioPersister.CreateDepot + Depot.Establish + Depot.Survey) — partial Slice B alone would have left gate=on operators with empty per-agency WOLF UI, so the activation pieces shipped together. Slice B-3 (0febbd98) shipped Depot.Negotiate hot-path debounce: the NegotiateProvider/NegotiateConsumer postfix coalesces ~10/s click-driven mutations into a single 250ms-tail debounced send + final-state guarantee on flush. Slice C (a9caea6e) shipped Routes per-agency: AgencyWolfRouteRouter (4-string composite key matching WOLF's GetRoute / HasRoute) + projector ROUTES splice with FK integrity sweep against depots (depotKeySet HashSet hoisted to projector method scope for Slice D/E reuse) + 3 Harmony postfixes + WolfRouteReflection cache + sender + AgencyMessageHandler stub + HarmonyPatcher.PatchWolfRoute. Slice D (f87ab3ab) shipped Hoppers + Terminals per-agency: AgencyWolfHopperRouter (FK-coupled to depots) + AgencyWolfTerminalRouter (no FK per source contract) + AgencyMsgReader dispatch slots 11+12 + 4 new sender methods + HandshakeSystem catchup chain extended to depots→routes→hoppers→terminals + AgencyScenarioProjector HOPPERS (FK-swept) + TERMINALS (unconditional) emit + 4 Harmony postfixes (Create/Remove × Hopper/Terminal). Slice E (d726dc46) shipped the distinctive Phase 4 surface: CrewRoutes per-agency + cross-agency kerbal authority gate (vessel-proxy authority via K1-pattern scan in AgencyWolfCrewRouter.BuildKerbalAgencyMap; mirrors KerbalSystem.CanRemoveKerbalUnderK1 from Stage 5.17e-8 — non-Empty-preserves-over-Empty rule against the launder-via-Empty grief vector). 5 client Harmony postfixes (Create/Embark/Disembark/Launch/CheckArrived); CheckArrived uses Harmony's __state pattern to detect the Enroute→Arrived auto-transition + emit exactly once (integration-logic-lens caught Slice E pre-spec missing this). Projector CREWROUTES emit with origin+destination FK sweep; depotKeySet build extracted to EnsureDepotKeySet local function shared by all 3 FK consumers (Routes/Hoppers/CrewRoutes). HandshakeSystem appends WOLF_ScenarioModule to SendScenariosToClient catchup so the reconnect window before the next projector tick is closed. Slice F (THIS slice) ships the migration helpers + closes Phase 4: AgencyWolfMigration.CascadeOnDelete invoked from DeleteAgencyCommand BEFORE TryDeleteAgency restores in-flight CrewRoute passengers (Enroute + Arrived per the WOLF Launch/CheckArrived state contract; Boarding skipped because those kerbals are still Assigned on their source vessel) from RosterStatus.Missing + SetTimeForRespawn(MaxValue) back to state=Available + ToD=0 via depth-aware kerbal-file rewrite. Per-kerbal isolation + outer try/catch ensures cascade exceptions never block the agency-file deletion (avoids orphan-file leak). transferagency + setvesselagency are NO-OPs for WOLF (AgencyId stable across owner-rename; WOLF entities are body+biome / Guid keyed not vessel-keyed; in-Enroute kerbal passenger lists are fixed at CreateCrewRoute time) — documented as XML comment blocks on each command class to prevent Slice G+ maintainers from adding redundant migration walks. v4 protocol stays at 0.31.0 throughout Phase 4 — 5 additive agency wire enum slots (9-13); 0.31.0 clients without the new slots fall through AgencyMsgReader's "unknown type" branch. Cross-agency depots/routes/hoppers/terminals partitioned cleanly via separate per-agency dicts. Dual-mode silence preserved at every router gate-check (TryRoute returns false under PerAgencyCareer=false; legacy 30s SHA pass operates unchanged). See docs/research/mks-lmp-compatibility-phase-4-prespec.md for the full spec; AgencyWolfMigration class XML for the Slice F kerbal-restoration contract + lock-domain discipline + operator-/kick-first race-window mitigation.
            "5.18g-hardening", // Stage 5.18g untrusted-cohort hardening. (1) AgencyCurrencyRouter rejects NaN / ±Infinity on Funds / Science / Reputation — finite values pass through unchanged (minimum-scope policy 2026-05-19; KSP + CC + KCT legitimately mutate scalars in wide ranges so no upper cap). On rejection, the unchanged authoritative AgencyState is echoed back via AgencyStateMsgData so the sender's local KSP singletons snap back; 5.18a client handler's StartIgnoringEvents bracket prevents feedback. (2) AgencyContractRouter adds a per-ContractGuid ConcurrentDictionary<Guid, Guid> claim map; first Accept wins via GetOrAdd; cross-agency collisions drop the contract from the batch with a Warning log. Closes the simultaneous-Accept race that the v3 relay fix (042d2cb5) made reachable in real-time peer-visible Offered. Pre-seeded on boot from each loaded AgencyState.Contracts via AgencyContractRouter.PreSeedClaimsFromAgencyState so post-restart claims survive. Evicted on /deleteagency via AgencyContractRouter.EvictClaimsForAgency so the deleted agency's id doesn't continue to "win" future re-Accepts of those guids. In-memory only (no disk write for the claim map itself; rebuilt from on-disk per-agency Contracts each boot). No periodic Completed/Failed/Cancelled eviction in v1 — entries persist for the server process lifetime (~32 bytes each, bounded by total Accepts); deleteagency eviction was added in this slice as a multi-lens review follow-up. (3) LmpClient/Windows/Status/StatusDrawer Agency-toggle gate adds `&& LocalAgencyId != Guid.Empty && LoadedScene >= SPACECENTER` so the toggle doesn't render between SettingsReply (ch 2) and AgencyHandshake (ch 22) arrivals AND mirrors AgencyWindow.Display's full predicate stack — v1 soak Finding 1 closure + integration-lens scene-divergence closure. CLIENT-ONLY visibility on (3); operators upgrading need to redeploy LmpClient.dll alongside the server build to pick up the StatusDrawer change. Dual-mode silence intact: gate=off, the currency router's TryResolveAgency short-circuits before RejectIfNonFinite runs; the contract router's gate-check at TryRoute returns false before _claimedContracts is consulted; the StatusDrawer's PerAgencyCareerEnabled gate hides the toggle entirely. Mod-compat surface unaffected — Contract Configurator's ContractPreLoader continues to drive the Offered/Generated pool unchanged (ApplySharedBatch path untouched); the claim guard intervenes only on the post-Accept transition.
            "per-agency-start-tech-seed", // 2026-05-20 v6 soak — per-agency Career players were missing the `start` tech node + its starter parts on first vessel launch, surfacing as KSP's "Unavailable Experimental Parts" dialog blocking mk1pod / parachuteSingle / basicFin / etc. Root cause: KSP auto-unlocks the `start` Tech node at Career-game-creation time without going through `ResearchAndDevelopment.UnlockTechWithParts`, so AgencyTechRouter.TryRoute never sees the unlock and AgencyState.TechNodes never gets a `start` entry — and the projector at AgencyScenarioProjector.cs:750-751 strips all Tech child nodes from outgoing R&D scenarios and only re-splices ones present in TechNodes. Fix: new `EnsureStartTechSeeded(AgencyState)` helper in AgencySystem.cs snapshots the canonical `start` Tech bytes from ScenarioStoreSystem.CurrentScenarios["ResearchAndDevelopment"] (under the per-scenario semaphore — BUG-033 contract) and inserts them into AgencyState.TechNodes + AgencyState.PurchasedParts under the per-agency lock. Called from both RegisterAgency (new-mint) AND LoadAgencyFromFile (boot + runtime load, backfills pre-fix agencies like the live Melaus case). Idempotent guard on TechNodes.ContainsKey("start") so re-loads are cheap; helper returns bool so callers do a single conditional SaveAgency instead of double-saving. Both TechNodes and PurchasedParts are seeded because the Tech bytes carry `part = X` lines that the projector splices verbatim, but KSP treats those as "part lives in this node" — separate from "purchased"; universes with non-zero entryCost on Start's parts would still lock the player out of using them. Helper logs Warning + skips on defensive paths (no shared scenario / no start child). Career-only via the existing PerAgencyEnabled gate (PerAgencyCareer && GameMode=Career). Dual-mode silence intact under gate=off / Sandbox / Science. Boot ordering verified: ScenarioStoreSystem.LoadExistingScenarios at MainServer.cs:97 runs BEFORE LoadExistingAgencies at MainServer.cs:110, so CurrentScenarios is populated when backfill runs. See docs/research/09-post-incident-systemic-improvements.md for the broader pattern this fix is a symptom of (assumptions about "all state mutations flow through wire paths we intercept" — KSP has multiple paths for the same operation) and the ranked backlog for prevention.
            "external-seat-sync", // 2026-05-20 — pre-existing bug uncovered during Stage 6 audit. CLIENT-ONLY fix; advertised here for operator banner visibility. Harmony patches at LmpClient/Harmony/KerbalEVA_BoardSeat.cs + KerbalEVA_OnDeboardSeat.cs raised ExternalSeatEvent.onExternalSeatBoard / onExternalSeatUnboard since 2018 but no subscriber existed — the original Dagger ExternalSeatSystem + ExternalSeatEvents were deleted in commit b7306514 (docking refactor collateral, not intentional). Result: when a kerbal sat down in an external command seat (lawn-chair on a rover), peers never saw it; the seat stayed empty across the network until the next periodic vessel resync (if any). Fix re-subscribes both events in LmpClient/Systems/VesselCrewSys/VesselCrewSystem with handlers in VesselCrewEvents that mirror the existing OnCrewBoard / CrewEvaReady shape. Board: SendVesselRemove(kerbalVesselId) + ReleaseAllVesselLocks + KillVessel + SendVesselMessage(seatOwnerVessel). Unboard: SendVesselMessage(unboardedSeatOwner) + FireOnCrewEvaReady(kerbalEvaInstance) — KSP's OnDeboardSeat does NOT reliably fire onCrewOnEva, so the explicit prime is required to broadcast the fresh EVA-kerbal vessel. No spectating-check on board (intentional; matches modern OnCrewBoard precedent — a peer might be boarding your seat). Per-agency interaction safe: under gate=on, cross-agency proto writes are already rejected by the v4 RejectIfCrossAgencyWrite in HandleVesselProto so Bob can't board Alice's lawn-chair into authoritative state — server treats it as a cosmetic-on-Bob's-client-only event, anti-grief intact. Operators upgrading need to redeploy LmpClient.dll to GameData/LunaMultiplayer/Plugins/ to pick up the change.
            "per-agency-kerbal-roster-scaffolding", // Stage 6 Phase 6.2 — settings + gate + boot-refusal scaffolding for the per-agency kerbal roster. Adds GameplaySettings.PerAgencyKerbalRoster (default false) + GameplaySettings.AllowEnablePerAgencyKerbalsOnExistingUniverse (default false) + AgencySystem.PerAgencyKerbalRosterEnabled combined-gate (composes PerAgencyEnabled AND PerAgencyKerbalRoster) + WarnAboutSharedKerbalsOnUpgrade boot diagnostic + RefuseStartupIfKerbalHazardWithoutOverride parallel fail-closed. The kerbal-roster override is INDEPENDENT of the existing AllowEnablePerAgencyOnExistingUniverse career-side override — the two operator decisions are orthogonal. Boot-refuse fires when PerAgencyKerbalRoster=true AND Universe/Kerbals/ contains *.txt files AND AllowEnablePerAgencyKerbalsOnExistingUniverse=false, regardless of Agencies.Count (unlike the career-side helpers which gate on Agencies.Count==0). Phase 6.2 lands the gate but NO handler reads it yet — HandleKerbalsRequest/Proto/Remove still write to the shared Universe/Kerbals/ path. Handler routing lands in Phase 6.4/6.5; lifecycle hooks (GetKerbalsPathForAgency + SeedStockKerbalsForAgency + mint/load/delete subdir handling) land in Phase 6.3. Spec at docs/research/10-stage6-per-agency-kerbals-spec.md. Dual-mode silence: default false everywhere, observably zero-change vs v7 unless the operator opts in. Difficulty presets (SetEasy/Normal/Moderate/Hard) all set both to false to avoid silent preset-flip on operator save. Setting a non-default value flips GameDifficulty=Custom on next save (documented behaviour per CLAUDE.md Settings caveat).
            "per-agency-kerbal-disk-layout", // Stage 6 Phase 6.3 — per-agency kerbal subdir + stock-4 seeding + delete-cascade. Adds AgencySystem.GetKerbalsPathForAgency(Guid) helper resolving to Universe/Agencies/{guid:N}/Kerbals/ (sibling of the {guid:N}.txt agency state file) + private SeedStockKerbalsForAgency(AgencyState) helper that idempotently writes Jeb/Bill/Bob/Val from Server.Properties.Resources.*_Kerman templates via FileHandler.WriteAtomic (per-file FileExists check supports partial-seed recovery). Wired into three lifecycle hooks: (a) RegisterAgency mints subdir + 4 files immediately after EnsureStartTechSeeded; (b) LoadAgencyFromFile backfills pre-Phase-6.3 agency files OR partial-seed recovery on every server boot or runtime LoadAgency; (c) TryDeleteAgency cascades the Kerbals subdir + empty parent {guid:N}/ folder along with the existing canonical-file unlink. New FileHandler.FolderDeleteRecursive helper wraps Directory.Delete(path, recursive: true) under the same per-path lock semaphore as FolderDelete (caller is responsible for the existence pre-check). Helpers gate on PerAgencyEnabled (PerAgencyCareer + Career mode) NOT the combined PerAgencyKerbalRosterEnabled — the disk layout is established up-front for every per-agency-career universe regardless of whether the operator has flipped PerAgencyKerbalRoster=true yet, so a mid-cohort flip needs no separate backfill pass. Phase 6.3 itself is observably silent: no handler reads the new subdir yet (HandleKerbalsRequest/Proto/Remove still route to Universe/Kerbals/), so per-agency-kerbal-roster behaviour stays bit-for-bit identical to Phase 6.2 / v7 even with the seed running. Storage cost ~4kB per agency of unused-but-correct stock kerbal files under PerAgencyKerbalRoster=false (negligible). Spec at docs/research/10-stage6-per-agency-kerbals-spec.md Phase 6.3 row + §3 lifecycle hook table.
        };
    }
